unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype)
{
	if( 0 == mype ) printf("Running event-based simulation...\n");

	unsigned long long verification = 0;

	#pragma omp parallel for schedule(dynamic, 32) reduction(+:verification)
	for( int i = 0; i < in.lookups; i++ )
	{
		// Set the initial seed value
		uint64_t seed = STARTING_SEED;

		// Forward seed to lookup index (we need 2 samples per lookup)
		seed = fast_forward_LCG(seed, 2*i);

		// Randomly pick an energy and material for the particle
		double p_energy = LCG_random_double(&seed);
		int mat         = pick_mat(&seed);

		double macro_xs_vector[5] = {0};

		// Perform macroscopic Cross Section Lookup
		calculate_macro_xs(
				p_energy,
				mat,
				in.n_isotopes,
				in.n_gridpoints,
				SD.num_nucs,
				SD.concs,
				SD.unionized_energy_array,
				SD.index_grid,
				SD.nuclide_grid,
				SD.mats,
				macro_xs_vector,
				in.grid_type,
				in.hash_bins,
				SD.max_num_nucs
				);

		double max = -1.0;
		int max_idx = 0;
		for(int j = 0; 5 > j; j++ )
		{
			if( max < macro_xs_vector[j] )
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification += max_idx + 1;
	}

	return verification;
}

unsigned long long run_history_based_simulation(Inputs in, SimulationData SD, int mype)
{
	if( 0 == mype ) printf("Running history-based simulation...\n");

	unsigned long long verification = 0;

	#pragma omp parallel for schedule(dynamic, 32) reduction(+:verification)
	for( int p = 0; p < in.particles; p++ )
	{
		// Each particle gets its own seed, forwarded by 2*lookups*p
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2LL * in.lookups * p);

		for( int l = 0; l < in.lookups; l++ )
		{
			// Sample energy and material for this lookup
			double p_energy = LCG_random_double(&seed);
			int mat         = pick_mat(&seed);

			double macro_xs_vector[5] = {0};

			calculate_macro_xs(
					p_energy,
					mat,
					in.n_isotopes,
					in.n_gridpoints,
					SD.num_nucs,
					SD.concs,
					SD.unionized_energy_array,
					SD.index_grid,
					SD.nuclide_grid,
					SD.mats,
					macro_xs_vector,
					in.grid_type,
					in.hash_bins,
					SD.max_num_nucs
					);

			double max = -1.0;
			int max_idx = 0;
			for(int j = 0; 5 > j; j++ )
			{
				if( max < macro_xs_vector[j] )
				{
					max = macro_xs_vector[j];
					max_idx = j;
				}
			}
			verification += max_idx + 1;
		}
	}

	return verification;
}

